# Example ablation: does quality filtering improve benchmark scores?
results = {
    "no_filter":          {"mmlu": 0.612, "hellaswag": 0.801, "ifeval": 0.541},
    "length_filter":      {"mmlu": 0.618, "hellaswag": 0.803, "ifeval": 0.563},
    "length+toxic_filter":{"mmlu": 0.621, "hellaswag": 0.802, "ifeval": 0.589},
    "full_pipeline":      {"mmlu": 0.624, "hellaswag": 0.805, "ifeval": 0.612},
}

print(f"{'Condition':<25} {'MMLU':>8} {'HellaSwag':>10} {'IFEval':>8}")
for condition, scores in results.items():
    print(f"{condition:<25} {scores['mmlu']:>8.3f} {scores['hellaswag']:>10.3f} {scores['ifeval']:>8.3f}")
